    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // 2. Calculate the total size needed: header size + items size
    const size_t header_size = sizeof(header);
    const size_t items_size = items.size() * sizeof(uint32_t);
    const size_t total_size = header_size + items_size;

    // 3. Check if buffer_adaptor has sufficient free space using the free() function
    if (adaptor.free() < total_size) {
