    }

    // 4. Create a binary_stream instance using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // 5. Write the header using binary_stream's operator<<
    stream << header;

    // 6. Write the items container using write_container function
    stream.write_container(items);

    return true; // Write successful
}
