std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file_buffer object using the provided file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer is in a valid state (no errors)
    if (!buffer) {
        return {}; // Return empty vector if file cannot be opened or error occurred
    }

    // Use the copy method to preview the header data without advancing the read pointer
    std::vector<uint8_t> header(header_size);

    // Check if requested header size exceeds available data
    if (header_size > buffer.size()) {
        // Adjust to available size if header_size is too large
        header.resize(buffer.size());
    }

    // Copy data without advancing read pointer
    if (!header.empty()) {
        buffer.copy(header.data(), header.size());

        // Check for errors during copy operation
        if (buffer.error()) {
            return {}; // Return empty vector on copy error
        }
    }

    return header;
}
```

